parameters.text:
=Act as an appointment booking assistant. Analyze the WhatsApp message and extract structured information.

Message from {{ $json.displayName }} ({{ $json.phoneNumber }}):
{{ $json.messageText }}

Extract and return ONLY a valid JSON object with these fields (no markdown, no explanation):
{"intent": "book or reschedule or confirm or cancel or unknown", "customerName": "extracted name or use displayName", "service": "haircut or massage or consultation or dental or general", "requestedDate": "YYYY-MM-DD or null", "requestedTime": "HH:MM in 24h or null", "existingAppointmentRef": "appointment ID or date for reschedule/confirm or null", "newDate": "YYYY-MM-DD for reschedule or null", "newTime": "HH:MM for reschedule or null", "notes": "special requests or empty string", "confidence": 0.9}

Today is {{ $json.receivedDate }}. Calculate actual dates for relative references like tomorrow or next Monday.

parameters.jsCode:
const item = $input.item.json;
const rawOutput = item.output || item.text || item.response || '{}';

let parsed;
try {
  const cleaned = rawOutput.replace(/```json|```/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = {
    intent: 'unknown',
    customerName: item.displayName || 'Guest',
    service: 'general',
    requestedDate: null,
    requestedTime: null,
    existingAppointmentRef: null,
    newDate: null,
    newTime: null,
    notes: '',
    confidence: 0
  };
}

return {
  json: {
    ...item,
    intent: parsed.intent || 'unknown',
    customerName: parsed.customerName || item.displayName || 'Guest',
    service: parsed.service || 'general',
    requestedDate: parsed.requestedDate || null,
    requestedTime: parsed.requestedTime || null,
    existingAppointmentRef: parsed.existingAppointmentRef || null,
    newDate: parsed.newDate || null,
    newTime: parsed.newTime || null,
    notes: parsed.notes || '',
    confidence: parsed.confidence || 0,
    appointmentId: 'APPT-' + Date.now()
  }
};

const item = $input.item.json;
const reqDate = item.requestedDate;
const reqTime = item.requestedTime;

if (!reqDate || !reqTime) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'Missing date or time in the booking request.', actionType: 'book' } };
}

const parts = reqTime.split(':').map(Number);
const hour = parts[0];
const dayOfWeek = new Date(reqDate).getDay();

if (dayOfWeek === 0 || dayOfWeek === 6) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'Appointments are not available on weekends. Please choose a weekday.', actionType: 'book' } };
}

if (hour < 9 || hour >= 18) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'Appointments are available between 9:00 AM and 6:00 PM only.', actionType: 'book' } };
}

const apptDate = new Date(reqDate);
const today = new Date();
today.setHours(0, 0, 0, 0);
if (apptDate < today) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'The requested date is in the past. Please choose a future date.', actionType: 'book' } };
}

return { json: { ...item, conflictCheckPassed: true, conflictReason: null, actionType: 'book' } };

const item = $input.item.json;
const newDate = item.newDate;
const newTime = item.newTime;
const ref = item.existingAppointmentRef;

if (!ref) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'Could not identify the existing appointment to reschedule. Please provide your original appointment date or ID.', actionType: 'reschedule' } };
}

if (!newDate || !newTime) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'Please provide the new date and time you would like to reschedule to.', actionType: 'reschedule' } };
}

const hour = parseInt(newTime.split(':')[0], 10);
const dayOfWeek = new Date(newDate).getDay();

if (dayOfWeek === 0 || dayOfWeek === 6) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'The new date falls on a weekend. Please choose a weekday.', actionType: 'reschedule' } };
}

if (hour < 9 || hour >= 18) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'New time must be between 9:00 AM and 6:00 PM.', actionType: 'reschedule' } };
}

return { json: { ...item, conflictCheckPassed: true, conflictReason: null, actionType: 'reschedule' } };

const item = $input.item.json;
const ref = item.existingAppointmentRef;

if (!ref) {
  return { json: { ...item, conflictCheckPassed: false, conflictReason: 'Could not find an appointment reference to confirm. Please share your appointment ID or date.', actionType: 'confirm' } };
}

return { json: { ...item, conflictCheckPassed: true, conflictReason: null, actionType: 'confirm' } };

const item = $input.item.json;
let replyMessage = '';

if (item.actionType === 'book') {
  if (item.conflictCheckPassed) {
    replyMessage = 'Appointment Booked! Hi ' + item.customerName + ', your appointment is confirmed.\nDate: ' + item.requestedDate + '\nTime: ' + item.requestedTime + '\nService: ' + item.service + '\nRef ID: ' + item.appointmentId + '\n\nReply CONFIRM ' + item.appointmentId + ' to confirm your slot.';
  } else {
    replyMessage = 'Booking Issue. Hi ' + item.customerName + ', we could not complete your booking.\nReason: ' + item.conflictReason + '\n\nPlease reply with your preferred date (YYYY-MM-DD) and time.';
  }
} else if (item.actionType === 'reschedule') {
  if (item.conflictCheckPassed) {
    replyMessage = 'Appointment Rescheduled! Hi ' + item.customerName + ', your appointment has been rescheduled.\nNew Date: ' + item.newDate + '\nNew Time: ' + item.newTime + '\nService: ' + item.service + '\n\nReply CONFIRM ' + item.existingAppointmentRef + ' to confirm your new slot.';
  } else {
    replyMessage = 'Reschedule Issue. Hi ' + item.customerName + ', we could not reschedule.\nReason: ' + item.conflictReason + '\n\nPlease provide your appointment ID and the new date and time you want.';
  }
} else if (item.actionType === 'confirm') {
  if (item.conflictCheckPassed) {
    replyMessage = 'Appointment Confirmed! Hi ' + item.customerName + ', your appointment is now confirmed.\nReference: ' + item.existingAppointmentRef + '\n\nWe will send you a reminder 24 hours before. See you soon!';
  } else {
    replyMessage = 'Confirmation Issue. Hi ' + item.customerName + ', we could not confirm.\nReason: ' + item.conflictReason + '\n\nPlease share your appointment ID or booking date.';
  }
} else {
  replyMessage = 'Welcome to Appointment Booking! Hi ' + (item.customerName || 'there') + ', I can help you:\n- Book a new appointment\n- Reschedule an existing one\n- Confirm your appointment\n\nExample: Book a haircut for tomorrow at 10 AM';
}

return {
  json: {
    ...item,
    replyMessage: replyMessage,
    finalStatus: item.conflictCheckPassed ? item.actionType.toUpperCase() + '_SUCCESS' : item.actionType.toUpperCase() + '_FAILED'
  }
};
